    int largestInteger(int num) {
        std::string s = std::to_string(num);
        std::vector<char> odd, even;
        for (char c : s) {
            if (c % 2 == 0) {
                even.push_back(c);
            } else {
                odd.push_back(c);
            }
        }
        std::sort(even.rbegin(), even.rend());
        std::sort(odd.rbegin(), odd.rend());
        int i = 0, j = 0;
        for (char c : s) {
            if (c % 2 == 0) {
                s[i++] = even[j++];
            } else {
                s[i++] = odd[j++];
            }
        }
        return std::stoi(s);
    }
};
